1	interface Item {
2	  type: string;
3	}
4	
5	interface QuoteStep {
6	  op: "quote";
7	  items: Item[];
8	}
9	
10	interface Scenario {
11	  customer: { yearsWithMHPCO: number };
12	  steps: QuoteStep[];
13	}
14	
15	const BASE_PREMIUM: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	};
21	
22	const COMPONENT_PREMIUM = 25;
23	const COMPONENT_BLOCK_SIZE = 3;
24	const COMPONENT_BLOCK_PREMIUM = 60;
25	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
26	
27	const FIRST_INSURANCE_SURCHARGE = 1.1;
28	const PROCESSING_FEE = 5;
29	
30	// Base premium for `count` alike components: a group of exactly 3 forms a
31	// block at COMPONENT_BLOCK_PREMIUM; otherwise each component costs
32	// COMPONENT_PREMIUM.
33	const componentGroupPremium = (count: number): number =>
34	  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
35	
36	const basePremium = (items: Item[]): number => {
37	  const componentCounts = new Map<string, number>();
38	  let total = 0;
39	  for (const item of items) {
40	    if (COMPONENT_TYPES.has(item.type)) {
41	      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
42	    } else {
43	      total += BASE_PREMIUM[item.type] ?? 0;
44	    }
45	  }
46	  for (const count of componentCounts.values()) {
47	    total += componentGroupPremium(count);
48	  }
49	  return total;
50	};
51	
52	// Round up to a whole number in MHPCO's favour, guarding against
53	// floating-point noise (e.g. 197.5000000001) before the ceiling.
54	const roundUpToWhole = (value: number): number => Math.ceil(Math.round(value * 1e6) / 1e6);
55	
56	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
57	  const results = scenario.steps.map((step) => {
58	    const base = basePremium(step.items);
59	    const premium = base * FIRST_INSURANCE_SURCHARGE + PROCESSING_FEE;
60	    return { premium: roundUpToWhole(premium) };
61	  });
62	  return { results };
63	};
